<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    :root {
      --bg: #f4f6f8;
      --surface: #ffffff;
      --text: #17202a;
      --muted: #6b7280;
      --border: #e3e8ee;
      --accent: #4f46e5;
      --accent-dark: #3730a3;
      --shadow: 0 8px 24px rgba(20, 31, 45, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      background: var(--bg);
      color: var(--text);
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .app {
      width: min(1180px, calc(100% - 32px));
      margin: 0 auto;
      padding: 42px 0 56px;
    }

    .topbar {
      display: flex;
      align-items: flex-end;
      justify-content: space-between;
      gap: 24px;
      margin-bottom: 28px;
    }

    h1 {
      margin: 0 0 7px;
      font-size: clamp(2rem, 4vw, 3rem);
      letter-spacing: -0.045em;
      line-height: 1;
    }

    .subtitle {
      margin: 0;
      color: var(--muted);
      font-size: 0.98rem;
    }

    .add-form {
      display: flex;
      gap: 10px;
      width: min(100%, 430px);
    }

    #new-card {
      min-width: 0;
      flex: 1;
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 12px 14px;
      background: var(--surface);
      color: var(--text);
      font: inherit;
      outline: none;
      box-shadow: 0 2px 6px rgba(20, 31, 45, 0.03);
    }

    #new-card:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.14);
    }

    #add-card {
      border: 0;
      border-radius: 10px;
      padding: 0 18px;
      background: var(--accent);
      color: white;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: background 0.2s ease, transform 0.2s ease;
    }

    #add-card:hover {
      background: var(--accent-dark);
    }

    #add-card:active {
      transform: translateY(1px);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 18px;
      align-items: start;
    }

    .column {
      min-height: 460px;
      padding: 16px;
      border: 1px solid var(--border);
      border-radius: 16px;
      background: #eef1f5;
      transition: background 0.2s ease, border-color 0.2s ease;
    }

    .column.drag-over {
      background: #e5e7ff;
      border-color: #aaa9f7;
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      margin: 1px 2px 15px;
    }

    .column-header h2 {
      margin: 0;
      font-size: 1rem;
      letter-spacing: -0.01em;
    }

    .count {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      min-width: 27px;
      height: 27px;
      padding: 0 8px;
      border-radius: 999px;
      background: #dce1e8;
      color: #4b5563;
      font-size: 0.8rem;
      font-weight: 800;
    }

    .card-list {
      display: flex;
      flex-direction: column;
      gap: 12px;
      min-height: 390px;
    }

    .card {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      padding: 15px 14px;
      border: 1px solid #e7ebf0;
      border-radius: 12px;
      background: var(--surface);
      box-shadow: var(--shadow);
      cursor: grab;
      user-select: none;
      transition: transform 0.18s ease, box-shadow 0.18s ease, opacity 0.18s ease;
    }

    .card:hover {
      transform: translateY(-2px);
      box-shadow: 0 12px 26px rgba(20, 31, 45, 0.12);
    }

    .card.dragging {
      opacity: 0.45;
      cursor: grabbing;
    }

    .card-title {
      overflow-wrap: anywhere;
      line-height: 1.45;
      font-size: 0.94rem;
    }

    .card-del {
      flex: 0 0 auto;
      width: 27px;
      height: 27px;
      border: 0;
      border-radius: 7px;
      background: transparent;
      color: #9aa3af;
      font-size: 1.2rem;
      line-height: 1;
      cursor: pointer;
      transition: background 0.2s ease, color 0.2s ease;
    }

    .card-del:hover {
      background: #fee2e2;
      color: #dc2626;
    }

    @media (max-width: 800px) {
      .topbar {
        align-items: stretch;
        flex-direction: column;
      }

      .add-form {
        width: 100%;
      }

      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 220px;
      }

      .card-list {
        min-height: 120px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header class="topbar">
      <div>
        <h1>Kanban Board</h1>
        <p class="subtitle">Organize your work and keep momentum moving.</p>
      </div>

      <form class="add-form" id="card-form">
        <input id="new-card" type="text" placeholder="Add a new card..." autocomplete="off">
        <button id="add-card" type="submit">Add card</button>
      </form>
    </header>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo" aria-labelledby="todo-heading">
        <div class="column-header">
          <h2 id="todo-heading">To Do</h2>
          <span class="count" aria-label="To Do card count">0</span>
        </div>
        <div class="card-list" aria-label="To Do cards"></div>
      </section>

      <section class="column" id="col-doing" aria-labelledby="doing-heading">
        <div class="column-header">
          <h2 id="doing-heading">In Progress</h2>
          <span class="count" aria-label="In Progress card count">0</span>
        </div>
        <div class="card-list" aria-label="In Progress cards"></div>
      </section>

      <section class="column" id="col-done" aria-labelledby="done-heading">
        <div class="column-header">
          <h2 id="done-heading">Done</h2>
          <span class="count" aria-label="Done card count">0</span>
        </div>
        <div class="card-list" aria-label="Done cards"></div>
      </section>
    </section>
  </main>

  <script>
    (() => {
      const STORAGE_KEY = "kanban-board-state";
      const columnIds = ["col-todo", "col-doing", "col-done"];
      const form = document.getElementById("card-form");
      const input = document.getElementById("new-card");
      let draggedCardId = null;

      function makeId() {
        return "card-" + Date.now() + "-" + Math.random().toString(36).slice(2, 9);
      }

      function updateCounts() {
        columnIds.forEach((columnId) => {
          const column = document.getElementById(columnId);
          const count = column.querySelector(".count");
          const cards = column.querySelectorAll(".card").length;
          count.textContent = cards;
          count.setAttribute("aria-label", `${cards} card${cards === 1 ? "" : "s"}`);
        });
      }

      function saveBoard() {
        const state = columnIds.map((columnId) => {
          const list = document.querySelector(`#${columnId} .card-list`);
          return {
            columnId,
            cards: Array.from(list.querySelectorAll(".card")).map((card) => ({
              id: card.dataset.id,
              title: card.querySelector(".card-title").textContent
            }))
          };
        });

        localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      }

      function createCard(title, id = makeId()) {
        const card = document.createElement("article");
        card.className = "card";
        card.draggable = true;
        card.dataset.id = id;

        const titleElement = document.createElement("span");
        titleElement.className = "card-title";
        titleElement.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.setAttribute("aria-label", `Delete ${title}`);
        deleteButton.title = "Delete card";
        deleteButton.textContent = "×";

        deleteButton.addEventListener("click", () => {
          card.remove();
          updateCounts();
          saveBoard();
        });

        card.addEventListener("dragstart", (event) => {
          draggedCardId = card.dataset.id;
          card.classList.add("dragging");
          event.dataTransfer.effectAllowed = "move";
          event.dataTransfer.setData("text/plain", draggedCardId);
        });

        card.addEventListener("dragend", () => {
          draggedCardId = null;
          card.classList.remove("dragging");
          document.querySelectorAll(".column").forEach((column) => {
            column.classList.remove("drag-over");
          });
        });

        card.append(titleElement, deleteButton);
        return card;
      }

      function loadBoard() {
        let savedState = null;

        try {
          savedState = JSON.parse(localStorage.getItem(STORAGE_KEY));
        } catch (error) {
          savedState = null;
        }

        if (!Array.isArray(savedState)) {
          updateCounts();
          return;
        }

        savedState.forEach((columnState) => {
          if (!columnIds.includes(columnState.columnId) || !Array.isArray(columnState.cards)) {
            return;
          }

          const list = document.querySelector(`#${columnState.columnId} .card-list`);
          columnState.cards.forEach((savedCard) => {
            if (savedCard && typeof savedCard.title === "string") {
              list.appendChild(createCard(savedCard.title, savedCard.id || makeId()));
            }
          });
        });

        updateCounts();
      }

      form.addEventListener("submit", (event) => {
        event.preventDefault();
        const title = input.value.trim();

        if (!title) {
          return;
        }

        document.querySelector("#col-todo .card-list").appendChild(createCard(title));
        input.value = "";
        updateCounts();
        saveBoard();
        input.focus();
      });

      document.querySelectorAll(".column").forEach((column) => {
        column.addEventListener("dragover", (event) => {
          event.preventDefault();
          event.dataTransfer.dropEffect = "move";
          column.classList.add("drag-over");
        });

        column.addEventListener("dragleave", (event) => {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", (event) => {
          event.preventDefault();
          column.classList.remove("drag-over");

          const idFromTransfer = event.dataTransfer.getData("text/plain");
          const cardId = idFromTransfer || draggedCardId;
          const card = document.querySelector(`.card[data-id="${CSS.escape(cardId)}"]`);

          if (!card) {
            return;
          }

          column.querySelector(".card-list").appendChild(card);
          updateCounts();
          saveBoard();
        });
      });

      loadBoard();
    })();
  </script>
</body>
</html>
